defmodule WebhookProxyController do
  use Phoenix.Controller

  def fetch_content(conn, params) do
    url = params["url"]

    # Allowlist expected hosts or domains
    allowed_hosts = ["example.com", "allowed-host.net"]
    if Enum.any?(allowed_hosts, fn host -> String.ends_with?(url, host) end) do
      # Resolve and reject loopback, link-local, multicast, and private IP destinations
      case :inet.parse_address(url) do
        {:ok, {_, _, _, _} = ip} ->
          if :inet.is_private(ip) or :inet.is_loopback(ip) or :inet.is_link_local(ip) or :inet.is_multicast(ip) do
            send_resp(conn, 400, "Invalid URL")
            return
          end

        {:error, _} ->
          # Disable redirects for security reasons
          case HTTPoison.get(url) do
            {:ok, %HTTPoison.Response{status_code: status}} when status in [301, 302] ->
              send_resp(conn, 400, "Redirects are not allowed")

            {:ok, %HTTPoison.Response{body: body}} ->
              send_resp(conn, 200, body)

            error ->
              send_resp(conn, 500, "Error fetching URL")
          end
      end

    else
      send_resp(conn, 400, "Invalid URL")
    end
  end
